import random, math, itertools, numpy as np
def prob_tail(w,p):
    m=len(w)
    pr=0.0
    for mask in range(1<<m):
        s=0.0; k=0
        for i in range(m):
            if mask>>i &1:
                s+=w[i]; k+=1
        if s+1e-12>=p:
            pr += (p**k)*((1-p)**(m-k))
    return pr
def random_weights(m):
    x=np.random.exponential(1,size=m)
    return x/x.sum()
