import numpy as np, math
def chernoff_bound(w,p):
    # minimize over t
    ts=np.linspace(0,200,20001)
    vals=[]
    for t in ts:
        log=t*p+sum(math.log(1-p+p*math.exp(-t*wi)) for wi in w)
        vals.append(log)
    mi=min(vals); t=ts[vals.index(mi)]
    return math.exp(mi),t
